import type * as DMMF from '@prisma/dmmf'

/**
 * Maps Prisma scalar type names to their TypeScript equivalents.
 * DateTime is represented as a string (ISO 8601) and Bytes as a string (base64) for REST wire compatibility.
 */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

export function dmmfScalarToTsType(typeName: string): string {
  return SCALAR_TYPE_MAP[typeName] ?? 'unknown'
}

/**
 * Returns the TypeScript type string for a scalar or enum DMMF field, accounting
 * for list and nullability. Returns null for relation (object) or unsupported fields,
 * which should be excluded from generated interfaces.
 */
export function dmmfFieldToTsType(field: DMMF.Field): string | null {
  if (field.kind === 'object' || field.kind === 'unsupported') return null

  const base = field.kind === 'enum' ? field.type : dmmfScalarToTsType(field.type)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

