import type * as DMMF from '@prisma/dmmf'

import { dmmfFieldToTsType, dmmfScalarToTsType } from '../type-utils'

/** Scalar and enum fields that map to a concrete TypeScript type (excludes relations and unsupported). */
function getTypedFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter((f) => dmmfFieldToTsType(f) !== null)
}

function buildEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

/** Full model interface with all scalar/enum fields. */
function buildModelInterface(model: DMMF.Model): string {
  const lines = getTypedFields(model).map((f) => {
    const tsType = dmmfFieldToTsType(f)!
    return `  ${f.name}${f.isRequired ? '' : '?'}: ${tsType};`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Input type for filtering in findMany queries.
 * All fields are optional; list fields are excluded as equality filters on arrays are uncommon.
 */
function buildWhereInput(model: DMMF.Model): string {
  const lines = getTypedFields(model)
    .filter((f) => !f.isList)
    .map((f) => {
      const base = f.kind === 'enum' ? f.type : dmmfScalarToTsType(f.type)
      const nullable = f.isRequired ? base : `${base} | null`
      return `  ${f.name}?: ${nullable};`
    })
  return `export interface ${model.name}WhereInput {\n${lines.join('\n')}\n}`
}

/** Input type for lookups by unique identifier. At least one field must be provided at runtime. */
function buildWhereUniqueInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => (f.isId || f.isUnique) && !f.isList && dmmfFieldToTsType(f) !== null)
    .map((f) => {
