import type * as DMMF from '@prisma/dmmf'

/** Converts a PascalCase model name to a camelCase property name (e.g. "PostComment" → "postComment"). */
function modelToPropertyName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

/** Lowercased plural used as the REST path segment (e.g. "User" → "users"). */
function modelToPathSegment(model: DMMF.Model): string {
  return model.name.toLowerCase() + 's'
}

/**
 * Returns a TypeScript expression (for the generated code) that resolves to the unique
 * identifier value from a `where` input object. Falls back to JSON-serialising the entire
 * `where` object when no `@id` or `@unique` scalar field is found.
 */
function buildIdExpression(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique && !f.isList)
  return idField ? `params.where.${idField.name}` : `JSON.stringify(params.where)`
}

function buildModelClientClass(model: DMMF.Model): string {
  const name = model.name
  const path = modelToPathSegment(model)
  const idExpr = buildIdExpression(model)

  // The backtick strings below use \` and \${ } to produce template literals in the generated code.
  return `export class ${name}RestClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: {
    where?: ${name}WhereInput
    skip?: number
    take?: number
    orderBy?: ${name}OrderByInput
  }): Promise<${name}[]> {
    const query = new URLSearchParams()
    if (params?.skip !== undefined) query.set('skip', String(params.skip))
    if (params?.take !== undefined) query.set('take', String(params.take))
    if (params?.where) query.set('where', JSON.stringify(params.where))
    if (params?.orderBy) query.set('orderBy', JSON.stringify(params.orderBy))
    const qs = query.toString()
    const res = await fetch(\`\${this.#baseUrl}/${path}\${qs ? '?' + qs : ''}\`)
    if (!res.ok) throw new Error(\`GET /${path} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(params: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {
    const id = ${idExpr}
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`GET /${path}/\${id} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create(params: { data: ${name}CreateInput }): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`POST /${path} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(params: { where: ${name}WhereUniqueInput; data: ${name}UpdateInput }): Promise<${name}> {
    const id = ${idExpr}
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`PUT /${path}/\${id} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(params: { where: ${name}WhereUniqueInput }): Promise<${name}> {
    const id = ${idExpr}
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {
      method: 'DELETE',
    })
    if (!res.ok) throw new Error(\`DELETE /${path}/\${id} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}`
}

function buildAggregatorClass(models: readonly DMMF.Model[]): string {
  const propDeclarations = models.map((m) => `  readonly ${modelToPropertyName(m.name)}: ${m.name}RestClient`).join('\n')
  const propAssignments = models
    .map((m) => `    this.${modelToPropertyName(m.name)} = new ${m.name}RestClient(this.#baseUrl)`)
    .join('\n')

  return `export class RestApiClient {
  #baseUrl: string
${propDeclarations}

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
${propAssignments}
  }
}`
}

/**
 * Generates the content of `rest-client.ts` — per-model REST client classes with typed
 * CRUD methods and a top-level `RestApiClient` aggregator that exposes one property per model.
 */
export function buildClientFile(dmmf: DMMF.Document): string {
  const { models } = dmmf.datamodel

  const allTypeNames = models.flatMap((m) => [
    m.name,
    `${m.name}WhereInput`,
    `${m.name}WhereUniqueInput`,
    `${m.name}CreateInput`,
    `${m.name}UpdateInput`,
    `${m.name}OrderByInput`,
  ])

  const importLine = `import type { ${allTypeNames.join(', ')} } from './types'`
  const modelClients = models.map(buildModelClientClass)
  const aggregator = buildAggregatorClass(models)

  return [importLine, ...modelClients, aggregator].join('\n\n') + '\n'
}

