import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { dmmfFieldToTsType, dmmfScalarToTsType } from '../type-utils'

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: 'String',
    ...overrides,
  } as DMMF.Field
}

describe('dmmfScalarToTsType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
  ])('maps %s → %s', (prismaType, tsType) => {
    expect(dmmfScalarToTsType(prismaType)).toBe(tsType)
  })

  it('returns "unknown" for unrecognised types', () => {
    expect(dmmfScalarToTsType('CustomType')).toBe('unknown')
  })
})

describe('dmmfFieldToTsType', () => {
  it('maps a required scalar field', () => {
