import { describe, expect, it } from 'vitest'

import { buildTypesFile } from '../generators/types-file'
import { testDmmf } from './fixtures'

describe('buildTypesFile', () => {
  it('emits enum union types', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits a model interface with only scalar and enum fields', () => {
    const output = buildTypesFile(testDmmf)
    // Relation field `posts` must not appear in the interface
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number;')
    expect(output).toContain('  email: string;')
    expect(output).toContain('  name?: string | null;')
    expect(output).toContain('  role: Role;')
    expect(output).toContain('  createdAt: string;')
    expect(output).not.toContain('posts')
  })

  it('emits WhereInput with all non-list scalar/enum fields optional', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface UserWhereInput {')
    expect(output).toContain('  id?: number;')
    expect(output).toContain('  email?: string;')
    expect(output).toContain('  name?: string | null;')
    expect(output).toContain('  role?: Role;')
  })

  it('emits WhereUniqueInput with only id and unique fields', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('  id?: number;')
    expect(output).toContain('  email?: string;')
    // Non-unique fields must not appear
    expect(output).not.toMatch(/UserWhereUniqueInput \{[^}]*  name\?/)
  })

  it('emits CreateInput excluding id/readOnly/generated/updatedAt fields', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface UserCreateInput {')
    // email is required without a default → mandatory
    expect(output).toContain('  email: string;')
    // name is optional
    expect(output).toContain('  name?: string | null;')
    // id has a default (autoincrement) → excluded (isId: true)
    expect(output).not.toMatch(/UserCreateInput \{[^}]*  id[?:]/)
    // authorId on Post is readOnly → excluded from PostCreateInput
    expect(output).toContain('export interface PostCreateInput {')
    expect(output).not.toMatch(/PostCreateInput \{[^}]*  authorId/)
  })

  it('emits UpdateInput with all editable fields as optional', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('  email?: string;')
    expect(output).toContain('  name?: string | null;')
    // id must not appear (isId: true)
    expect(output).not.toMatch(/UserUpdateInput \{[^}]*  id[?:]/)
  })

  it('emits OrderByInput with asc/desc for non-list fields', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface UserOrderByInput {')
    expect(output).toContain("  id?: 'asc' | 'desc';")
    expect(output).toContain("  email?: 'asc' | 'desc';")
  })

  it('generates interfaces for all models', () => {
    const output = buildTypesFile(testDmmf)
    expect(output).toContain('export interface Post {')
    expect(output).toContain('export interface PostWhereInput {')
    expect(output).toContain('export interface PostCreateInput {')
  })
})

