describe('buildClientFile', () => {
  it('imports all model types from ./types', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain("import type {")
    expect(output).toContain("} from './types'")
    // Spot-check a few type names in the import
    expect(output).toContain('User')
    expect(output).toContain('UserWhereInput')
    expect(output).toContain('UserCreateInput')
    expect(output).toContain('PostWhereUniqueInput')
  })

  it('generates a RestClient class for each model', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('export class UserRestClient {')
    expect(output).toContain('export class PostRestClient {')
  })

  it('generates findMany with correct signature', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('async findMany(params?: {')
    expect(output).toContain('where?: UserWhereInput')
    expect(output).toContain('skip?: number')
    expect(output).toContain('take?: number')
    expect(output).toContain('orderBy?: UserOrderByInput')
    expect(output).toContain('): Promise<User[]>')
  })

  it('generates findUnique with correct signature', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('async findUnique(params: { where: UserWhereUniqueInput }): Promise<User | null>')
    // Uses the @id field as the path parameter
    expect(output).toContain('const id = params.where.id')
  })

  it('generates create with correct signature', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('async create(params: { data: UserCreateInput }): Promise<User>')
    expect(output).toContain("method: 'POST'")
  })

  it('generates update with correct signature', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain(
      'async update(params: { where: UserWhereUniqueInput; data: UserUpdateInput }): Promise<User>',
    )
    expect(output).toContain("method: 'PUT'")
  })

  it('generates delete with correct signature', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('async delete(params: { where: UserWhereUniqueInput }): Promise<User>')
    expect(output).toContain("method: 'DELETE'")
  })

  it('uses fetch with the correct REST path segment', () => {
    const output = buildClientFile(testDmmf)
    // User → /users, Post → /posts
    expect(output).toContain('/users')
    expect(output).toContain('/posts')
  })

  it('generates the top-level RestApiClient aggregator', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('readonly user: UserRestClient')
    expect(output).toContain('readonly post: PostRestClient')
    expect(output).toContain('this.user = new UserRestClient(this.#baseUrl)')
    expect(output).toContain('this.post = new PostRestClient(this.#baseUrl)')
  })

  it('uses native private field #baseUrl (not the private keyword)', () => {
    const output = buildClientFile(testDmmf)
    expect(output).toContain('#baseUrl')
    // Should not use TypeScript `private` keyword for the base URL field
    expect(output).not.toContain('private baseUrl')
  })
})

