async findMany(params?: {
  where?: ${name}WhereInput
  skip?: number
  take?: number
  orderBy?: ${name}OrderByInput
}): Promise<${name}[]> {
  const query = new URLSearchParams()
  if (params?.skip !== undefined) query.set('skip', String(params.skip))
  if (params?.take !== undefined) query.set('take', String(params.take))
  if (params?.where) query.set('where', JSON.stringify(params.where))
  if (params?.orderBy) query.set('orderBy', JSON.stringify(params.orderBy))
  const qs = query.toString()
  const res = await fetch(\`\${this.#baseUrl}/${path}\${qs ? '?' + qs : ''}\`)
  if (!res.ok) throw new Error(\`GET /${path} failed: \${res.status} \${res.statusText}\`)
  return res.json() as Promise<${name}[]>
}

