import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { buildClientFile } from './generators/client-file'
import { buildIndexFile } from './generators/index-file'
import { buildTypesFile } from './generators/types-file'

export interface FileMap {
  [name: string]: string | Buffer | FileMap
}

const missingOutputErrorMessage = `An output path is required for the \`rest-api-client\` generator. Please provide one in your schema file:

  generator restClient {
    provider = "rest-api-client"
    output   = "../src/generated/rest-client"
  }
`

async function writeFileMap(outputDir: string, fileMap: FileMap): Promise<void> {
  await Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)
      // Delete first so editors (e.g. VS Code) reliably pick up the change.
      await fs.rm(absolutePath, { recursive: true, force: true })
      if (typeof content === 'string' || Buffer.isBuffer(content)) {
        await fs.writeFile(absolutePath, content)
      } else {
        await fs.mkdir(absolutePath)
        await writeFileMap(absolutePath, content)
      }
    }),
  )
}

/** Resolves the output directory, deletes stale contents, and writes the generated file map. */
export async function generateRestApiClient(options: GeneratorOptions): Promise<void> {
  if (!options.generator.output) {
    throw new Error(missingOutputErrorMessage)
  }

  const outputDir = parseEnvValue(options.generator.output)

  const fileMap: FileMap = {
    'types.ts': buildTypesFile(options.dmmf),
    'rest-client.ts': buildClientFile(options.dmmf),
    'index.ts': buildIndexFile(options.dmmf.datamodel.models),
  }

  await fs.rm(outputDir, { recursive: true, force: true })
  await fs.mkdir(outputDir, { recursive: true })
  await writeFileMap(outputDir, fileMap)
}
